mapper.select:
SELECT id, name, state, product_id, product_qty, qty_produced, bom_id, finished_location_id, origin_ref, component_cost, finished_cost, company_id FROM mrp_production
AND bom_id = #{query.bomId}
AND product_id = #{query.productId}
AND company_id = #{query.companyId}
AND origin_ref = #{query.originRef}
AND ( name ILIKE CONCAT('%', #{query.keyword}, '%') OR origin_ref ILIKE CONCAT('%', #{query.keyword}, '%') )
ORDER BY id DESC
